import{_ as e,o as i,c as s,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Features","description":"","frontmatter":{"summary":"OpenSoul capabilities across channels, routing, media, and UX.","read_when":["You want a full list of what OpenSoul supports"],"title":"Features"},"headers":[],"relativePath":"concepts/features.md","filePath":"concepts/features.md","lastUpdated":null}'),t={name:"concepts/features.md"};function o(l,a,r,d,h,c){return i(),s("div",null,[...a[0]||(a[0]=[n('<h2 id="highlights" tabindex="-1"><a class="header-anchor" href="#highlights">#</a> Highlights</h2><h3 id="_30-channels" tabindex="-1"><a class="header-anchor" href="#_30-channels">#</a> 30+ Channels</h3><p>WhatsApp, Telegram, Discord, Slack, iMessage, Signal, Matrix, and more with a single Gateway.</p><h3 id="_50-skills" tabindex="-1"><a class="header-anchor" href="#_50-skills">#</a> 50+ Skills</h3><p>GitHub, Notion, Obsidian, Canvas, 1Password, and extensible plugin SDK.</p><h3 id="multi-agent-routing" tabindex="-1"><a class="header-anchor" href="#multi-agent-routing">#</a> Multi-agent routing</h3><p>Isolated sessions per agent, workspace, or sender.</p><h3 id="media" tabindex="-1"><a class="header-anchor" href="#media">#</a> Media</h3><p>Images, audio, and documents in and out.</p><h3 id="cross-platform-apps" tabindex="-1"><a class="header-anchor" href="#cross-platform-apps">#</a> Cross-platform apps</h3><p>Web Control UI, macOS, Windows, iOS, Android, CLI/TUI.</p><h3 id="mobile-nodes" tabindex="-1"><a class="header-anchor" href="#mobile-nodes">#</a> Mobile nodes</h3><p>iOS and Android nodes with Canvas support.</p><h2 id="full-list" tabindex="-1"><a class="header-anchor" href="#full-list">#</a> Full list</h2><h3 id="channels-30" tabindex="-1"><a class="header-anchor" href="#channels-30">#</a> Channels (30+)</h3><ul><li>WhatsApp (Baileys), Telegram (grammY), Discord, Slack, Signal, iMessage (BlueBubbles)</li><li>Mattermost, Matrix, LINE, Zalo, Feishu, Google Chat, Microsoft Teams (plugins)</li><li>Nextcloud Talk, Nostr, Twitch, WebChat, REST API, WebSocket</li></ul><h3 id="agent-core" tabindex="-1"><a class="header-anchor" href="#agent-core">#</a> Agent core</h3><ul><li>Pi agent in RPC mode with tool streaming</li><li>Multi-model support: OpenAI, Anthropic, AWS Bedrock, Ollama (local), and more</li><li>Memory system with vector search (LanceDB)</li><li>Multi-agent routing for isolated sessions per workspace or sender</li><li>Subscription auth for Anthropic and OpenAI via OAuth</li><li>Sessions: direct chats collapse into shared <code>main</code>; groups are isolated</li><li>Group chat support with mention-based activation</li><li>Streaming and chunking for long responses</li></ul><h3 id="media-and-voice" tabindex="-1"><a class="header-anchor" href="#media-and-voice">#</a> Media and voice</h3><ul><li>Images, audio, and documents in and out</li><li>Optional voice note transcription</li><li>Voice Call extension with TTS/STT</li></ul><h3 id="apps-and-ui" tabindex="-1"><a class="header-anchor" href="#apps-and-ui">#</a> Apps and UI</h3><ul><li>Web Control UI and WebChat</li><li>macOS menu bar app</li><li>Windows native desktop app (WPF)</li><li>iOS and Android nodes with pairing and Canvas</li><li>CLI and TUI for power users</li></ul><blockquote><p><strong>Note:</strong> Legacy Claude, Codex, Gemini, and Opencode paths have been removed. Pi is the only coding agent path.</p></blockquote>',23)])])}const m=e(t,[["render",o]]);export{u as __pageData,m as default};
